import{_ as e,o as s,c as n,a2 as t}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"통합 패턴 (Integration)","description":"","frontmatter":{},"headers":[],"relativePath":"hermes/integration/index.md","filePath":"hermes/integration/index.md","lastUpdated":1781092690000}'),i={name:"hermes/integration/index.md"};function p(l,a,o,r,d,c){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="통합-패턴-integration" tabindex="-1">통합 패턴 (Integration) <a class="header-anchor" href="#통합-패턴-integration" aria-label="Permalink to &quot;통합 패턴 (Integration)&quot;">​</a></h1><div class="badge-box"><span class="badge-red">Integration</span><span class="badge-teal">Practical</span><span class="badge-gold">Production</span></div><blockquote><p>Hermes Agent를 <strong>다른 시스템에 붙이는 실전 패턴</strong>을 모아둔 섹션입니다. 공식 문서가 &quot;Hermes가 무엇을 하는가&quot;를 설명한다면, 이 섹션은 &quot;내 제품에 Hermes를 어떻게 태울 것인가&quot;를 다룹니다.</p></blockquote><h2 id="언제-hermes를-붙여야-하는가" tabindex="-1">언제 Hermes를 붙여야 하는가 <a class="header-anchor" href="#언제-hermes를-붙여야-하는가" aria-label="Permalink to &quot;언제 Hermes를 붙여야 하는가&quot;">​</a></h2><p>자체 AI 에이전트를 처음부터 만들지, Hermes를 통합할지 결정하는 기준.</p><div class="two-col"><div class="col-card"><h4>Hermes 통합이 적합</h4><ul><li>에이전트가 <strong>도구를 호출해 실제 작업</strong>을 수행해야 함</li><li>학습 루프·스킬·메모리 같은 인프라를 직접 만들기 싫음</li><li>모델 프로바이더 중립성이 필요</li><li>15+ 메시징 플랫폼 접점이 선택사항이라도 필요</li><li>MCP 생태계에 합류하고 싶음</li><li>오픈소스 MIT 라이선스 기반이어야 함</li></ul></div><div class="col-card"><h4>직접 구현이 적합</h4><ul><li>단순 챗봇 (도구 호출 없음)</li><li>특정 모델 SDK에 완전히 종속된 기능이 필요</li><li>Python 3.11+를 못 올리는 환경</li><li>매우 좁은 도메인 (Aider, SweAgent처럼 한 가지만)</li><li>추상화 오버헤드 없이 최소 레이어 원함</li></ul></div></div><h2 id="주요-통합-경로" tabindex="-1">주요 통합 경로 <a class="header-anchor" href="#주요-통합-경로" aria-label="Permalink to &quot;주요 통합 경로&quot;">​</a></h2><p>Hermes는 여러 통합 진입점을 제공합니다. 각각의 특성과 적합한 시나리오:</p><h3 id="_1-http-api-openai-호환-—-가장-범용" tabindex="-1">1. HTTP API (OpenAI 호환) — 가장 범용 <a class="header-anchor" href="#_1-http-api-openai-호환-—-가장-범용" aria-label="Permalink to &quot;1. HTTP API (OpenAI 호환) — 가장 범용&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Your App ──▶ POST /v1/chat/completions ──▶ hermes serve</span></span></code></pre></div><p><strong>언제 쓰는가</strong>: 대부분의 경우. 웹앱, 백엔드 서비스, CLI 도구, CI 파이프라인 모두 가능합니다. OpenAI SDK를 쓰는 기존 코드도 <code>base_url</code> 한 줄만 바꾸면 됩니다.</p><p>→ 자세한 것은 <a href="/hermes/features/api-server">API 서버 (OpenAI 호환)</a></p><h3 id="_2-web-ui-bff-패턴-—-사용자-ui" tabindex="-1">2. Web UI (BFF 패턴) — 사용자 UI <a class="header-anchor" href="#_2-web-ui-bff-패턴-—-사용자-ui" aria-label="Permalink to &quot;2. Web UI (BFF 패턴) — 사용자 UI&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser ◀─WebSocket─▶ BFF ──HTTP──▶ hermes serve</span></span></code></pre></div><p><strong>언제 쓰는가</strong>: 사용자가 터미널이 아닌 브라우저에서 에이전트와 상호작용해야 할 때. 도구 결과를 풍부하게 렌더링하고 승인 UX가 필요한 경우.</p><p>→ 자세한 것은 <a href="/hermes/integration/web-ui">Web UI 통합 패턴</a></p><h3 id="_3-게이트웨이-메시징-플랫폼" tabindex="-1">3. 게이트웨이 (메시징 플랫폼) <a class="header-anchor" href="#_3-게이트웨이-메시징-플랫폼" aria-label="Permalink to &quot;3. 게이트웨이 (메시징 플랫폼)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Telegram/Discord/Slack ──▶ Hermes Gateway ──▶ Agent Core</span></span></code></pre></div><p><strong>언제 쓰는가</strong>: 이미 존재하는 메시징 워크플로우에 에이전트를 끼워 넣고 싶을 때. UI를 만들 필요가 없습니다.</p><p>→ 자세한 것은 <a href="/hermes/features/gateway">멀티 플랫폼 게이트웨이</a></p><h3 id="_4-acp-ide-protocol" tabindex="-1">4. ACP (IDE Protocol) <a class="header-anchor" href="#_4-acp-ide-protocol" aria-label="Permalink to &quot;4. ACP (IDE Protocol)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VS Code / Zed / JetBrains ──ACP──▶ hermes acp</span></span></code></pre></div><p><strong>언제 쓰는가</strong>: 에이전트를 코딩 어시스턴트로 IDE에 통합할 때. 일반 앱에는 부적합.</p><p>→ 자세한 것은 <a href="/hermes/advanced/acp">ACP (IDE 통합)</a></p><h3 id="_5-mcp-서버-모드-에이전트-투-에이전트" tabindex="-1">5. MCP 서버 모드 (에이전트-투-에이전트) <a class="header-anchor" href="#_5-mcp-서버-모드-에이전트-투-에이전트" aria-label="Permalink to &quot;5. MCP 서버 모드 (에이전트-투-에이전트)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Agent ──MCP──▶ hermes mcp-server</span></span></code></pre></div><p><strong>언제 쓰는가</strong>: 다른 에이전트 프레임워크(LangChain, CrewAI, 커스텀)가 Hermes를 <strong>하위 전문가</strong>로 호출해야 할 때. 드문 케이스.</p><p>→ 자세한 것은 <a href="/hermes/advanced/mcp#hermes가-mcp-서버-되기-v0-6-0">MCP 서버 연동</a></p><h3 id="_6-크론-게이트웨이-헤드리스-자동화" tabindex="-1">6. 크론 + 게이트웨이 (헤드리스 자동화) <a class="header-anchor" href="#_6-크론-게이트웨이-헤드리스-자동화" aria-label="Permalink to &quot;6. 크론 + 게이트웨이 (헤드리스 자동화)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cron Scheduler ──▶ Agent Core ──▶ message-send</span></span></code></pre></div><p><strong>언제 쓰는가</strong>: UI 없는 완전 자동화. 정기 리포트, 알림, 모니터링.</p><p>→ 자세한 것은 <a href="/hermes/features/cron">크론 스케줄러</a></p><h2 id="통합-의사결정-트리" tabindex="-1">통합 의사결정 트리 <a class="header-anchor" href="#통합-의사결정-트리" aria-label="Permalink to &quot;통합 의사결정 트리&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자가 에이전트와 직접 상호작용하는가?</span></span>
<span class="line"><span>├── 아니오 (자동화만)</span></span>
<span class="line"><span>│   └── 크론 + 게이트웨이</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── 예</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    어떤 UI에서?</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 터미널 → CLI 기본 제공</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── IDE → ACP</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 메시징 앱 (Slack, Telegram) → 게이트웨이</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── 웹 브라우저</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        기존 OpenAI 클라이언트 코드가 있는가?</span></span>
<span class="line"><span>        ├── 예 → API 서버 직결 (base_url만 변경)</span></span>
<span class="line"><span>        └── 아니오 → BFF 패턴 (Web UI 통합)</span></span></code></pre></div><h2 id="공통-고려사항" tabindex="-1">공통 고려사항 <a class="header-anchor" href="#공통-고려사항" aria-label="Permalink to &quot;공통 고려사항&quot;">​</a></h2><p>어느 경로를 택하든 피할 수 없는 설계 결정:</p><dl class="kv"><dt>세션 전략</dt><dd>per-user / per-project / per-tab — <a href="/integration/web-ui#세션-관리-전략">Web UI 가이드</a>에서 자세히</dd><dt>인증·권한</dt><dd>Hermes 자체는 단일 사용자를 가정 — 멀티 사용자는 통합 레이어에서 구현</dd><dt>승인 UX</dt><dd>CLI는 텍스트, 메시징은 버튼, 웹은 모달 — 승인 정책은 동일하게</dd><dt>비용 통제</dt><dd>사용자별 쿼터·모델 게이팅·폴백 체인</dd><dt>도구 격리</dt><dd>Docker/Modal 백엔드로 도구 실행을 샌드박스에</dd><dt>관측성</dt><dd>턴별 latency·토큰·에러율·승인 대기 시간 수집</dd></dl><h2 id="섹션-페이지" tabindex="-1">섹션 페이지 <a class="header-anchor" href="#섹션-페이지" aria-label="Permalink to &quot;섹션 페이지&quot;">​</a></h2><ul><li><a href="/hermes/integration/web-ui"><strong>Web UI 통합 패턴</strong></a> — 브라우저 기반 사용자 UI를 만드는 BFF 아키텍처, React 예제, 승인 플로우, 도구 결과 렌더링, 배포</li></ul><div class="info custom-block"><p class="custom-block-title">추가 예정</p><p>이 섹션은 지속 업데이트됩니다. 다음 통합 가이드가 추가될 예정:</p><ul><li>백엔드 서비스 통합 (Node.js / Go / Python)</li><li>CI 파이프라인 통합 (GitHub Actions, GitLab CI)</li><li>모바일 앱 통합 (React Native, Flutter)</li><li>LangChain / LlamaIndex 상호 운용</li></ul></div>`,40)])])}const g=e(i,[["render",p]]);export{u as __pageData,g as default};
